const input = $input.first()?.json ?? {};
const source = input.query ?? input;
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const parseNumber = (value) => {
  const normalized = clean(value).replace(/,/g, '');
  if (!normalized) return null;
  const parsed = Number.parseFloat(normalized);
  return Number.isFinite(parsed) ? parsed : null;
};
const parseDateInput = (value) => {
  const raw = clean(value);
  if (!raw) return '';
  if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) return raw;
  const match = raw.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (!match) return raw;
  const [, day, month, year] = match;
  return `${year}-${month.padStart(2, '0')}-${day.padStart(2, '0')}`;
};
return [{
  json: {
    name: clean(source.name),
    refund_for: clean(source.refund_for ?? source.for_name ?? source.for),
    reason: clean(source.reason),
    membership: clean(source.membership),
    amount: parseNumber(source.amount),
    from_date: parseDateInput(source.from_date ?? source.fromDate),
    to_date: parseDateInput(source.to_date ?? source.toDate),
    status: clean(source.status) || 'Requested',
    created_by: clean(source.created_by) || 'refund_webhook'
  }
}];

const item = $input.first()?.json ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const sqlLiteral = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'";
};
const sqlNumeric = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return String(Number(value));
};
const parseIsoDate = (value) => {
  const raw = clean(value);
  const match = raw.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!match) return null;
  const [, yearText, monthText, dayText] = match;
  const year = Number.parseInt(yearText, 10);
  const month = Number.parseInt(monthText, 10);
  const day = Number.parseInt(dayText, 10);
  if (!Number.isInteger(year) || !Number.isInteger(month) || !Number.isInteger(day)) return null;
  if (month < 1 || month > 12 || day < 1 || day > 31) return null;
  return { year, month, day, iso: `${yearText}-${monthText}-${dayText}` };
};
const formatMoney = (value) => {
  const rounded = Math.round((Number(value) + Number.EPSILON) * 100) / 100;
  const text = Number.isInteger(rounded) ? String(rounded) : rounded.toFixed(2).replace(/\.00$/, '').replace(/(\.\d)0$/, '$1');
  return `£${text}`;
};
const fail = (message) => [{ json: { sql: `select false as ok, 400 as response_code, ${sqlLiteral(message)}::text as message;` } }];
if (!clean(item.name)) return fail('name is required');
if (!clean(item.refund_for)) return fail('refund_for is required');
if (!clean(item.reason)) return fail('reason is required');
if (!clean(item.membership)) return fail('membership is required');
if (item.amount === null || !Number.isFinite(Number(item.amount)) || Number(item.amount) < 0) return fail('amount must be a valid number greater than or equal to zero');
const fromDate = parseIsoDate(item.from_date);
const toDate = parseIsoDate(item.to_date);
if (!fromDate) return fail('from_date must be a valid date');
if (!toDate) return fail('to_date must be a valid date');
const fromMonthNumber = (fromDate.year * 12) + fromDate.month;
const toMonthNumber = (toDate.year * 12) + toDate.month;
const months = toMonthNumber - fromMonthNumber;
if (months < 1) return fail('to_date must be at least one calendar month after from_date');
const refund = Math.round((Number(item.amount) * Math.max(months - 1, 0)) / 12);
const explanation = `Refund of membership. Reason Player ${clean(item.reason)}. Repayment = ${formatMoney(item.amount)} * (${months}-1)/12 months = ${formatMoney(refund)}`;
return [{
  json: {
    sql: `with inserted as (
  insert into public.refunds (
    name,
    refund_for,
    reason,
    membership,
    amount,
    from_date,
    to_date,
    months,
    refund,
    status,
    explanation,
    created_by
  ) values (
    ${sqlLiteral(item.name)},
    ${sqlLiteral(item.refund_for)},
    ${sqlLiteral(item.reason)},
    ${sqlLiteral(item.membership)},
    ${sqlNumeric(item.amount)},
    ${sqlLiteral(fromDate.iso)}::date,
    ${sqlLiteral(toDate.iso)}::date,
    ${months},
    ${sqlNumeric(refund)},
    ${sqlLiteral(item.status)},
    ${sqlLiteral(explanation)},
    ${sqlLiteral(item.created_by)}
  )
  returning id, name, refund_for, reason, membership, amount, from_date, to_date, months, refund, status, explanation, created_at
)
select true as ok, 200 as response_code, format('Added refund %s', id) as message, *
from inserted;`
  }
}];
